    /**
     * Expand compact county data to full jurisdiction format.
     * @param {string} stateFips - Two-digit state FIPS
     * @param {Object} compact - Compact county entry {n, t, f, c, z, p}
     * @returns {Object} Full jurisdiction object
     */
    function expand(stateFips, compact) {
        return {
            name: compact.n,
            type: compact.t,
            fips: compact.f,
            stateCountyFips: stateFips + compact.f,
            namePatterns: compact.p,
            mapCenter: compact.c,
            mapZoom: compact.z,
            maintainsOwnRoads: true
        };
    }

    return {
        /**
         * Get all counties for a state in full jurisdiction format.
         * @param {string} stateFips - Two-digit state FIPS code
         * @returns {Object|null} Counties keyed by ID, or null if state not found
         */
        getCounties(stateFips) {
            const padded = String(stateFips).padStart(2, '0');
            const stateData = COUNTIES[padded];
            if (!stateData) return null;

            const result = {};
            for (const [id, compact] of Object.entries(stateData)) {
                result[id] = expand(padded, compact);
            }
            return result;
        },

        /**
         * Check if a state has county data available.
         * @param {string} stateFips - Two-digit state FIPS code
         * @returns {boolean}
         */
        hasState(stateFips) {
            const padded = String(stateFips).padStart(2, '0');
            return !!COUNTIES[padded];
        },

        /**
         * Get count of counties for a state.
         * @param {string} stateFips
         * @returns {number}
         */
        getCountyCount(stateFips) {
            const padded = String(stateFips).padStart(2, '0');
            const stateData = COUNTIES[padded];
            return stateData ? Object.keys(stateData).length : 0;
        },

        /**
         * Get total number of states in the database.
         * @returns {number}
         */
        get stateCount() {
            return Object.keys(COUNTIES).length;
        },

        /**
         * Get total number of counties across all states.
         * @returns {number}
         */
        get totalCounties() {
            let total = 0;
            for (const stateData of Object.values(COUNTIES)) {
                total += Object.keys(stateData).length;
            }
            return total;
        }
    };
